import*as THREE from 'three';export class Cube{constructor(scene){this.cube_size;this.mvm;this.start_pos;this.time_offset;this.duration;this.t=0;this.global_scale=1;this.bg_grid_size=5;this.squish=0.5;const geometry=new THREE.BoxGeometry(1,1,1);this.fill_col=window.getComputedStyle(document.body,null).getPropertyValue('--theme');this.point_col=window.getComputedStyle(document.body,null).getPropertyValue('--primary-noalpha');const material=new THREE.MeshBasicMaterial({color:this.fill_col});this.object=new THREE.Mesh(geometry,material);this.object.position.set(0,0,0);this.object.userData=this;this.points=[];}
update(){this.t+=0.001;let q=this.t/this.duration;q=ease(q,2);let scl=this.cube_size*this.global_scale;let mat=new THREE.Matrix4().identity();mat.premultiply(this.action(q));let e=new THREE.Euler(special_constant,-Math.PI*0.25,0,'XYZ');let e_=new THREE.Euler(Math.PI*0.25,-special_constant,0,'YXZ');mat.premultiply(new THREE.Matrix4().makeRotationFromEuler(e));mat.premultiply(new THREE.Matrix4().makeTranslation(this.start_pos));mat.premultiply(new THREE.Matrix4().makeScale(scl,scl,scl));this.object.position.set(0,0,0);this.object.rotation.set(0,0,0);this.object.applyMatrix4(mat);let scl_vec=new THREE.Vector3().setFromMatrixScale(mat);this.object.scale.set(scl_vec.x,scl_vec.y,scl_vec.z);for(let point of this.points){let i=point.userData.x;let j=point.userData.y;let k=point.userData.z;let v=new THREE.Vector3(i*1.0/this.cube_size-0.5,j*1.0/this.cube_size-0.5,k*1.0/this.cube_size-0.5);point.position.set(v.x,v.y,v.z);point.rotation.set(0,0,0);point.applyMatrix4(mat);point.applyMatrix4(new THREE.Matrix4().makeTranslation(0,0,2));point.scale.set(1,1,1);}}
update_cols(){this.fill_col=window.getComputedStyle(document.body,null).getPropertyValue('--theme');this.point_col=window.getComputedStyle(document.body,null).getPropertyValue('--primary-noalpha');;this.object.material.color.set(this.fill_col);for(let point of this.points)
point.material.color.set(this.point_col);}
make_new_cube(){this.t=0;this.cube_size=randint(1,5);this.mvm=randint(0,10);this.start_pos=random_pos(Math.floor(this.bg_grid_size*0.4)-1);this.time_offset=rand(0,1);this.duration=0.08+0.1*((this.cube_size-1)/(5-1));this.points=[];for(let i=0;i<this.cube_size+1;i++)
for(let j=0;j<this.cube_size+1;j++)
for(let k=0;k<this.cube_size+1;k++){if(Math.min(i,j,k)>0&&Math.max(i,j,k)<this.cube_size)
continue;const geometry=new THREE.SphereGeometry(0.2,10,10);const material=new THREE.MeshBasicMaterial({color:this.point_col});const sphere=new THREE.Mesh(geometry,material);sphere.userData=new THREE.Vector3(i,j,k);this.points.push(sphere);}}
action(q){let mat=new THREE.Matrix4().identity();if(this.mvm==0){mat.premultiply(new THREE.Matrix4().makeTranslation(-0.5,0.5,0));mat.premultiply(new THREE.Matrix4().makeRotationZ(-Math.PI*0.5*q));mat.premultiply(new THREE.Matrix4().makeTranslation(0.5,-0.5,0));}else if(this.mvm==1){mat.premultiply(new THREE.Matrix4().makeTranslation(0,0.5,-0.5));mat.premultiply(new THREE.Matrix4().makeRotationX(Math.PI*0.5*q));mat.premultiply(new THREE.Matrix4().makeTranslation(0,-0.5,0.5));}else if(this.mvm==2){mat.premultiply(new THREE.Matrix4().makeTranslation(0.5,0.5,0));mat.premultiply(new THREE.Matrix4().makeRotationZ(-Math.PI*0.5*q));mat.premultiply(new THREE.Matrix4().makeTranslation(-0.5,-0.5,0));}else if(this.mvm==3){mat.premultiply(new THREE.Matrix4().makeTranslation(0,0.5,0.5));mat.premultiply(new THREE.Matrix4().makeRotationX(Math.PI*0.5*q));mat.premultiply(new THREE.Matrix4().makeTranslation(0,-0.5,-0.5));}else if(this.mvm==4){mat.premultiply(new THREE.Matrix4().makeTranslation(-0.5,0,0.5));mat.premultiply(new THREE.Matrix4().makeRotationY(Math.PI*0.5*q));mat.premultiply(new THREE.Matrix4().makeTranslation(0.5,0,-0.5));}else if(this.mvm==5){mat.premultiply(new THREE.Matrix4().makeTranslation(0.5,0,-0.5));mat.premultiply(new THREE.Matrix4().makeRotationY(-Math.PI*0.5*q));mat.premultiply(new THREE.Matrix4().makeTranslation(-0.5,0,0.5));}else if(this.mvm==6){mat.premultiply(new THREE.Matrix4().makeTranslation(0.5,0,0.5));mat.premultiply(new THREE.Matrix4().makeRotationY(Math.PI*0.5*q));mat.premultiply(new THREE.Matrix4().makeTranslation(-0.5,0,-0.5));}else if(this.mvm==7){mat.premultiply(new THREE.Matrix4().makeTranslation(0.5,0,0.5));mat.premultiply(new THREE.Matrix4().makeRotationY(Math.PI*0.5*q));mat.premultiply(new THREE.Matrix4().makeTranslation(-0.5,0,-0.5));}else if(this.mvm==8){mat.premultiply(new THREE.Matrix4().makeTranslation(0.5,0,0));mat.premultiply(new THREE.Matrix4().makeScale(q,1,1));mat.premultiply(new THREE.Matrix4().makeTranslation(-0.5,0,0));}else if(this.mvm==9){mat.premultiply(new THREE.Matrix4().makeTranslation(0,0,0.5));mat.premultiply(new THREE.Matrix4().makeScale(1,1,q));mat.premultiply(new THREE.Matrix4().makeTranslation(0,0,-0.5));}else if(this.mvm==10){mat.premultiply(new THREE.Matrix4().makeTranslation(0,0.5,0));mat.premultiply(new THREE.Matrix4().makeScale(1,q,1));mat.premultiply(new THREE.Matrix4().makeTranslation(0,-0.5,0));}
return mat;}}
const special_constant=0.6154797086703873410674645891239936;function ease(p,g){if(p<0.5)
return 0.5*Math.pow(2*p,g);else
return 1-0.5*Math.pow(2*(1-p),g);}
function in_grid(i,j,rad){return-j<1+i+rad&&(j-rad-1)<-i;}
function transform(v){let amt=1;return rotX(rotY(v,Math.PI*0.25*amt),-special_constant*amt);}
function untransform(v){let amt=1;return rotY(rotX(v,special_constant*amt),-Math.PI*0.25*amt);}
function global_transform(v,global_scale){return transform(v.multiplyScalar(global_scale));}
function grid_to_isom(v){let amt=1;let C1=Math.cos(-Math.PI*0.25*amt);let S12=Math.sin(-Math.PI*0.25*amt)*Math.sin(-special_constant*amt);let C2=Math.cos(-special_constant*amt);return new THREE.Vector3(C1*v.x,S12*v.x-C2*v.y);}
function isom_to_grid(v){let amt=1;let C1=cos(-Math.PI*0.25*amt);let S12=sin(-Math.PI*0.25*amt)*sin(-special_constant*amt);let C2=cos(-special_constant*amt);return new PVector(v.x/C1,(-S12*v.x/C1/C2+v.y/C2));}
function scrolling(v){return v;}
function rotX(v,th){return v.applyAxisAngle(new THREE.Vector3(1,0,0),th);}
function rotY(v,th){return v.applyAxisAngle(new THREE.Vector3(0,1,0),th);}
function rotZ(v,th){return v.applyAxisAngle(new THREE.Vector3(0,0,1),th);}
function randint(a,b){return Math.floor(Math.random()*(b-a+1))+a;}
function rand(a,b){return Math.floor(Math.random()*(b-a+1))+a;}
function random_pos(rad){let x=randint(-rad,rad);let y=randint(-rad,rad);while(!in_grid(x,y,rad)){x=randint(-rad,rad);y=randint(-rad,rad);}
let v=(grid_to_isom(new THREE.Vector2(x,y)));return v;}